insert into creatures (id, name, description, image_url, is_custom, user_id) values
('c0010000-0000-0000-0000-000000000001', 'Clownfish', 'Bright orange fish with white stripes that lives among sea anemones. Made famous by finding Nemo.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/242892/medium.jpg', false, null),
('c0020000-0000-0000-0000-000000000002', 'Blue Tang', 'Vivid blue surgeonfish with a yellow tail. Feeds on algae and is an important reef cleaner.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/109563/medium.jpg', false, null),
('c0030000-0000-0000-0000-000000000003', 'Green Sea Turtle', 'Large herbivorous sea turtle found in tropical and subtropical seas worldwide.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/6035/medium.jpg', false, null),
('c0040000-0000-0000-0000-000000000004', 'Hawksbill Sea Turtle', 'Critically endangered sea turtle with a narrow pointed beak, used to extract food from crevices.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/13965/medium.jpg', false, null),
('c0050000-0000-0000-0000-000000000005', 'Manta Ray', 'Graceful giant of the ocean with wingspan up to 7 meters. Feeds on plankton by filter feeding.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/19622/medium.jpg', false, null),
('c0060000-0000-0000-0000-000000000006', 'Whale Shark', 'The largest fish in the ocean, reaching 12+ meters. Gentle filter feeder despite its massive size.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/19818/medium.jpg', false, null),
('c0070000-0000-0000-0000-000000000007', 'Nurse Shark', 'Bottom-dwelling shark often found resting motionless on sandy floors. Docile and slow-moving.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/2946/medium.jpg', false, null),
('c0080000-0000-0000-0000-000000000008', 'Reef Shark (Blacktip)', 'Sleek shark easily identified by the black tips on its fins. Common in shallow reef environments.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/4234/medium.jpg', false, null),
('c0090000-0000-0000-0000-000000000009', 'Hammerhead Shark', 'Instantly recognizable by its wide, flat, hammer-shaped head. Usually spotted in schools.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/6124/medium.jpg', false, null),
('c0100000-0000-0000-0000-000000000010', 'Moray Eel', 'Serpentine predators with powerful jaws that hide in reef crevices and emerge to ambush prey.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/2897/medium.jpg', false, null),
('c0110000-0000-0000-0000-000000000011', 'Octopus', 'Highly intelligent cephalopod with 8 arms, able to change color and texture in milliseconds.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/3045/medium.jpg', false, null),
('c0120000-0000-0000-0000-000000000012', 'Giant Pacific Octopus', 'The world''s largest octopus species, reaching arm spans of over 4 meters. Lives in cold Pacific waters.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/8231/medium.jpg', false, null),
('c0130000-0000-0000-0000-000000000013', 'Blue-Ringed Octopus', 'Tiny but deadly octopus whose iridescent blue rings flash as a warning before it strikes.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/7892/medium.jpg', false, null),
('c0140000-0000-0000-0000-000000000014', 'Cuttlefish', 'Masters of camouflage that can ripple color patterns across their skin in real time.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/4567/medium.jpg', false, null),
('c0150000-0000-0000-0000-000000000015', 'Nautilus', 'Living fossil with a spiral shell chambered for buoyancy. Swims via jet propulsion.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/12034/medium.jpg', false, null),
('c0160000-0000-0000-0000-000000000016', 'Lionfish', 'Striking red-and-white striped fish with venomous spines. An invasive species in the Atlantic.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/5678/medium.jpg', false, null),
('c0170000-0000-0000-0000-000000000017', 'Stonefish', 'World''s most venomous fish, camouflaged as a rock on the seafloor. Extremely difficult to spot.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/9012/medium.jpg', false, null),
('c0180000-0000-0000-0000-000000000018', 'Leafy Sea Dragon', 'Ornate relative of the seahorse with leaf-like appendages that provide perfect camouflage in kelp.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/11234/medium.jpg', false, null),
('c0190000-0000-0000-0000-000000000019', 'Seahorse', 'Unique fish where the male carries and births the young. Anchors itself to coral with its prehensile tail.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/3456/medium.jpg', false, null),
('c0200000-0000-0000-0000-000000000020', 'Pufferfish', 'Can inflate itself into a spiky ball when threatened. Highly toxic flesh despite being a culinary delicacy.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/6789/medium.jpg', false, null),
('c0210000-0000-0000-0000-000000000021', 'Parrotfish', 'Colorful fish that bites off chunks of coral, digests the algae, and excretes white sand.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/7123/medium.jpg', false, null),
('c0220000-0000-0000-0000-000000000022', 'Humphead Wrasse', 'Massive fish with a distinctive hump on its forehead. One of the largest reef fish, up to 2 meters.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/8901/medium.jpg', false, null),
('c0230000-0000-0000-0000-000000000023', 'Triggerfish (Clown)', 'Bold yellow, white and black pattern. Known for aggressively defending its nest territory.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/9345/medium.jpg', false, null),
('c0240000-0000-0000-0000-000000000024', 'Barracuda', 'Fast, torpedo-shaped predator with sharp teeth. Often seen in schools or cruising reef edges alone.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/4890/medium.jpg', false, null),
('c0250000-0000-0000-0000-000000000025', 'Giant Grouper', 'One of the largest reef fish, capable of swallowing small sharks whole. Slow but powerful.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/5012/medium.jpg', false, null),
('c0260000-0000-0000-0000-000000000026', 'Stingray', 'Flat-bodied ray that glides along sandy bottoms. The venomous barb at the tail base is only used defensively.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/2345/medium.jpg', false, null),
('c0270000-0000-0000-0000-000000000027', 'Eagle Ray', 'Spotted ray with a long whip tail that ''flies'' gracefully through the water column.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/3678/medium.jpg', false, null),
('c0280000-0000-0000-0000-000000000028', 'Electric Ray', 'Can generate up to 220 volts of electricity to stun prey and defend itself.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/6234/medium.jpg', false, null),
('c0290000-0000-0000-0000-000000000029', 'Jellyfish (Moon)', 'Translucent, pulsing umbrella-shaped jellyfish with a mild sting. One of the most common species worldwide.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/4123/medium.jpg', false, null),
('c0300000-0000-0000-0000-000000000030', 'Lion''s Mane Jellyfish', 'World''s largest jellyfish with tentacles up to 37 meters long. Lives in cold northern waters.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/9567/medium.jpg', false, null),
('c0310000-0000-0000-0000-000000000031', 'Box Jellyfish', 'One of the most venomous creatures on Earth. Cube-shaped bell with trailing tentacles loaded with toxins.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/8456/medium.jpg', false, null),
('c0320000-0000-0000-0000-000000000032', 'Sea Lion', 'Playful and curious marine mammal that often approaches divers. Expert underwater acrobat.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/2678/medium.jpg', false, null),
('c0330000-0000-0000-0000-000000000033', 'Dolphin', 'Highly intelligent marine mammal. Occasionally investigates divers and may swim alongside for minutes.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/1890/medium.jpg', false, null),
('c0340000-0000-0000-0000-000000000034', 'Sperm Whale', 'Deepest-diving whale, capable of descending to 3,000+ meters. Has the largest brain of any animal.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/7345/medium.jpg', false, null),
('c0350000-0000-0000-0000-000000000035', 'Humpback Whale', 'Famous for its haunting songs and dramatic breaching leaps. Seasonally spotted on diver routes.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/5890/medium.jpg', false, null),
('c0360000-0000-0000-0000-000000000036', 'Dugong', 'Gentle marine mammal that grazes on seagrass. The real-life inspiration for mermaid legends.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/6456/medium.jpg', false, null),
('c0370000-0000-0000-0000-000000000037', 'Nudibranch (Spanish Dancer)', 'Flamboyantly colored sea slug that undulates through the water like a flamenco dancer.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/3901/medium.jpg', false, null),
('c0380000-0000-0000-0000-000000000038', 'Nudibranch (Chromodoris)', 'Jewel-like sea slug in electric blue, white and black. A favorite subject for macro photography.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/4678/medium.jpg', false, null),
('c0390000-0000-0000-0000-000000000039', 'Frogfish', 'Ambush predator that mimics sponges and coral. Among the fastest strikers in the animal kingdom.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/7890/medium.jpg', false, null),
('c0400000-0000-0000-0000-000000000040', 'Mantis Shrimp', 'Punches with the force of a bullet and can see 16 types of color (humans see 3). Vivid and aggressive.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/5123/medium.jpg', false, null),
('c0410000-0000-0000-0000-000000000041', 'Lobster', 'Large crustacean often found sheltering under ledges. Moves forward slowly but can swim backward rapidly.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/2901/medium.jpg', false, null),
('c0420000-0000-0000-0000-000000000042', 'Decorator Crab', 'Camouflages itself by attaching living sponges and anemones to its shell — a mobile garden.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/8012/medium.jpg', false, null),
('c0430000-0000-0000-0000-000000000043', 'Porcelain Crab', 'Tiny filter feeder with oversized claws that often lives inside sea anemones like clownfish.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/9234/medium.jpg', false, null),
('c0440000-0000-0000-0000-000000000044', 'Crown of Thorns Starfish', 'Large venomous starfish that preys on coral polyps. Population explosions can devastate entire reefs.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/6012/medium.jpg', false, null),
('c0450000-0000-0000-0000-000000000045', 'Sea Urchin (Black Longspine)', 'Covered in long sharp spines. A grazer that controls algae growth and provides shelter for small fish.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/3234/medium.jpg', false, null),
('c0460000-0000-0000-0000-000000000046', 'Sea Cucumber', 'Cylindrical bottom-dweller that processes sediment for nutrients. Ejects sticky threads when threatened.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/4456/medium.jpg', false, null),
('c0470000-0000-0000-0000-000000000047', 'Feather Star (Crinoid)', 'Ancient relative of starfish with feathery arms that filter food from the current. Lives on reef edges.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/5678/medium.jpg', false, null),
('c0480000-0000-0000-0000-000000000048', 'Basket Star', 'Complex branching brittle star that unfurls its fractal arms at night to catch plankton.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/7012/medium.jpg', false, null),
('c0490000-0000-0000-0000-000000000049', 'Giant Clam', 'World''s largest bivalve, reaching 1.2 meters and living for over a century. Farms algae in its mantle.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/8234/medium.jpg', false, null),
('c0500000-0000-0000-0000-000000000050', 'Cone Snail', 'Beautiful spiral shell hiding one of the ocean''s most potent venoms. Fires a harpoon-like tooth.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/9456/medium.jpg', false, null),
('c0510000-0000-0000-0000-000000000051', 'Flatworm (Polyclad)', 'Paper-thin, brilliantly colored worm that glides over the reef surface. Often mistaken for nudibranchs.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/6678/medium.jpg', false, null),
('c0520000-0000-0000-0000-000000000052', 'Christmas Tree Worm', 'Spiral feathery gills extend from a tube buried in coral. Instantly retracts when approached.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/3890/medium.jpg', false, null),
('c0530000-0000-0000-0000-000000000053', 'Cleaner Shrimp', 'Sets up ''cleaning stations'' on the reef where fish line up to have parasites removed.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/5234/medium.jpg', false, null),
('c0540000-0000-0000-0000-000000000054', 'Harlequin Shrimp', 'Striking white shrimp with blue-edged spots that hunts starfish — including crown of thorns.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/7456/medium.jpg', false, null),
('c0550000-0000-0000-0000-000000000055', 'Mimic Octopus', 'Impersonates other species including lionfish and flatfish to deter predators. Extreme intelligence.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/8678/medium.jpg', false, null),
('c0560000-0000-0000-0000-000000000056', 'Bioluminescent Plankton', 'Microscopic organisms that glow electric blue when disturbed in the dark. Night divers'' magic.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/9890/medium.jpg', false, null),
('c0570000-0000-0000-0000-000000000057', 'Wobbegong Shark', 'Carpet shark with a flattened body and elaborate skin flaps that make it nearly invisible on the seafloor.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/6890/medium.jpg', false, null),
('c0580000-0000-0000-0000-000000000058', 'Bumphead Parrotfish', 'Massive parrotfish that schools in large groups and headbutts coral to scrape off algae.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/4012/medium.jpg', false, null),
('c0590000-0000-0000-0000-000000000059', 'Tasseled Wobbegong', 'Ornately fringed ambush predator that lies flat on the reef, almost indistinguishable from the substrate.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/2123/medium.jpg', false, null),
('c0600000-0000-0000-0000-000000000060', 'Oarfish', 'World''s longest bony fish, reaching 11 meters. Lives in the deep and is rarely seen alive by divers.', 'https://inaturalist-open-data.s3.amazonaws.com/photos/1234/medium.jpg', false, null);
